  1	import * as React from 'react';
  2	import { ReplicationType } from '@odf/mco/constants';
  3	import { getDRPolicyStatus } from '@odf/mco/utils';
  4	import { SingleSelectDropdown } from '@odf/shared/dropdown/singleselectdropdown';
  5	import { getName } from '@odf/shared/selectors';
  6	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
  7	import { getValidatedProp } from '@odf/shared/utils';
  8	import { TFunction } from 'react-i18next';
  9	import {
 10	  Form,
 11	  FormGroup,
 12	  FormHelperText,
 13	  HelperText,
 14	  HelperTextItem,
 15	  SelectOption,
 16	} from '@patternfly/react-core';
 17	import {
 18	  ManagePolicyStateAction,
 19	  ManagePolicyStateType,
 20	  ModalViewContext,
 21	} from '../utils/reducer';
 22	import { DRPolicyType } from '../utils/types';
 23	
 24	const getDropdownOptions = (dataPolicies: DRPolicyType[], t: TFunction) =>
 25	  dataPolicies.map((policy) => (
 26	    <SelectOption
 27	      key={getName(policy)}
 28	      value={getName(policy)}
 29	      description={
 30	        policy.replicationType === ReplicationType.ASYNC
 31	          ? t(
 32	              'Replication type: {{type}}, Interval: {{interval}}, Clusters: {{clusters}}',
 33	              {
 34	                type: policy.replicationType,
 35	                interval: policy.schedulingInterval,
 36	                clusters: policy.drClusters.join(', '),
 37	              }
 38	            )
 39	          : t('Replication type: {{type}}, Clusters: {{clusters}}', {
 40	              type: policy.replicationType,
 41	              clusters: policy.drClusters.join(', '),
 42	            })
 43	      }
 44	    >
 45	      {getName(policy)}
 46	    </SelectOption>
 47	  ));
 48	
 49	export const findPolicy = (name: string, dataPolicies: DRPolicyType[]) =>
 50	  dataPolicies.find((policy) => getName(policy) === name);
 51	
 52	export const SelectPolicyWizardContent: React.FC<
 53	  SelectPolicyWizardContentProps
 54	> = ({ policy, matchingPolicies, isValidationEnabled, dispatch }) => {
 55	  const { t } = useCustomTranslation();
 56	  const name = getName(policy);
 57	  const isInvalidPolicy = isValidationEnabled && !name;
 58	  return (
 59	    <Form className="mco-manage-policies__form--width">
 60	      <FormGroup
 61	        fieldId="policy-type-selector"
 62	        label={t('Policy name')}
 63	        isRequired
 64	      >
 65	        <SingleSelectDropdown
 66	          placeholderText={t('Select a policy')}
 67	          selectOptions={getDropdownOptions(matchingPolicies, t)}
 68	          id="policy-selection-dropdown"
 69	          selectedKey={name}
 70	          validated={getValidatedProp(isInvalidPolicy)}
 71	          required
 72	          onChange={(value: string) => {
 73	            if (name !== value) {
 74	              dispatch({
 75	                type: ManagePolicyStateType.SET_SELECTED_POLICY,
 76	                context: ModalViewContext.ASSIGN_POLICY_VIEW,
 77	                payload: findPolicy(value, matchingPolicies),
 78	              });
 79	            }
 80	          }}
 81	        />
 82	        <FormHelperText>
 83	          <HelperText>
 84	            <HelperTextItem>
 85	              {!!policy &&
 86	                t('Status: {{status}}', {
 87	                  status: getDRPolicyStatus(policy.isValidated, t),
 88	                })}
 89	            </HelperTextItem>
 90	            {isInvalidPolicy && (
 91	              <HelperTextItem variant={getValidatedProp(isInvalidPolicy)}>
 92	                {t('Required')}
 93	              </HelperTextItem>
 94	            )}
 95	          </HelperText>
 96	        </FormHelperText>
 97	      </FormGroup>
 98	    </Form>
 99	  );
100	};
101	
102	type SelectPolicyWizardContentProps = {
103	  policy: DRPolicyType;
104	  matchingPolicies: DRPolicyType[];
105	  isValidationEnabled: boolean;
106	  dispatch: React.Dispatch<ManagePolicyStateAction>;
107	};

